func writeCookieAuth(t *testing.T, home string) {
	t.Helper()
	dir := filepath.Join(home, ".config", "x-twitter-pp-cli")
	if err := os.MkdirAll(dir, 0o700); err != nil {
		t.Fatalf("mkdir cookie dir: %v", err)
	}
	data := []byte(`{"auth_token":"cookie-auth","ct0":"csrf","web_bearer":"web","user_id":"123","captured_at":"2026-06-07"}`)
	if err := os.WriteFile(filepath.Join(dir, "cookies.json"), data, 0o600); err != nil {
		t.Fatalf("write cookies: %v", err)
	}
}

func testXAuthProbeServer() *httptest.Server {
	return httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		auth := r.Header.Get("Authorization")
		switch r.URL.Path {
		case "/2/users/me":
			switch auth {
			case "Bearer user":
				w.Header().Set("Content-Type", "application/json")
				_, _ = w.Write([]byte(`{"data":{"id":"123","username":"tester"}}`))
			case "Bearer app", "Bearer app-as-user":
				http.Error(w, xUnsupportedAppOnlyBody, http.StatusForbidden)
			default:
				http.Error(w, "invalid token", http.StatusUnauthorized)
			}
		case xAppOnlyProbePath:
			if auth == "Bearer app" {
				w.Header().Set("Content-Type", "application/json")
				_, _ = w.Write([]byte(`{"data":{"id":"2244994945","username":"TwitterDev"}}`))
				return
			}
			http.Error(w, "invalid token", http.StatusUnauthorized)
		default:
			http.NotFound(w, r)
		}
	}))
}

